import React from 'react';

export default function Logo({ size = 38 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 38 38" fill="none" img="./photo.png">
      <circle cx="19" cy="19" r="18" fill="#1A2E3B" stroke="#3AABDC" strokeWidth="1" />
      <path d="M19 8 L19 30" stroke="#3AABDC" strokeWidth="2.5" strokeLinecap="round" />
      <path d="M8 19 Q13 10 19 8 Q25 10 30 19" stroke="#8DC63F" strokeWidth="2" fill="none" strokeLinecap="round" />
      <path d="M8 19 Q13 28 19 30 Q25 28 30 19" stroke="#3AABDC" strokeWidth="2" fill="none" strokeLinecap="round" />
      <circle cx="19" cy="19" r="3" fill="#8DC63F" />
    </svg>
  );
}
